func readDepsFile(path string) ([]string, error) {
	f, err := os.Open(path)
	if err != nil {
		return nil, err
	}
	defer f.Close()

	var out []string
	sc := bufio.NewScanner(f)
	for sc.Scan() {
		line := strings.TrimSpace(sc.Text())
		if line == "" || strings.HasPrefix(line, "#") {
			continue
		}
		if i := strings.Index(line, "#"); i >= 0 {
			line = strings.TrimSpace(line[:i])
		}
		if line != "" {
			out = append(out, line)
		}
	}
	return out, sc.Err()
}

func parseCSV(s string) []string {
	var out []string
	for _, part := range strings.Split(s, ",") {
		p := strings.TrimSpace(part)
		if p != "" {
			out = append(out, p)
		}
	}
	return out
}

func isInsecure(pkg string, prefixes []string) bool {
	for _, pre := range prefixes {
		if pre == "" {
			continue
		}
		if strings.HasPrefix(pkg, pre) {
			return true
		}
		if strings.HasPrefix(pkg, "https://"+pre) || strings.HasPrefix(pkg, "http://"+pre) {
			return true
		}
		if strings.HasPrefix(pkg, pre+"/") {
			return true
		}
	}
	return false
}

func runCmd(ctx context.Context, dir string, env []string, name string, args ...string) error {
	cmd := exec.CommandContext(ctx, name, args...)
	cmd.Dir = dir
	cmd.Env = env

	var buf bytes.Buffer
	cmd.Stdout = os.Stdout
	cmd.Stderr = &buf

	err := cmd.Run()
	if err == nil {
		return nil
	}

	if buf.Len() > 0 {
		os.Stderr.Write(buf.Bytes())
	}

	if errors.Is(ctx.Err(), context.DeadlineExceeded) {
		return fmt.Errorf("timeout: %w", ctx.Err())
	}
	if ee := new(exec.ExitError); errors.As(err, &ee) {
		return fmt.Errorf("exit code %d", ee.ExitCode())
	}
	return err
}

func baseEnv(in []string) []string {
	out := make([]string, 0, len(in)+8)
	out = append(out, in...)
	if runtime.GOOS == "windows" {
		out = normalizeWindowsEnv(out)
	}
	return out
}

func normalizeWindowsEnv(env []string) []string {
	seen := map[string]int{}
	out := make([]string, 0, len(env))
	for _, kv := range env {
		k := strings.SplitN(kv, "=", 2)[0]
		ku := strings.ToUpper(k)
		if idx, ok := seen[ku]; ok {
			out[idx] = kv
			continue
		}
		seen[ku] = len(out)
		out = append(out, kv)
	}
	return out
}

func setEnv(env []string, key, val string) []string {
	prefix := key + "="
	for i := range env {
		if strings.HasPrefix(env[i], prefix) {
			env[i] = prefix + val
			return env
		}
	}
	return append(env, prefix+val)
}

func getenvFrom(env []string, key string) string {
	prefix := key + "="
	for _, kv := range env {
		if strings.HasPrefix(kv, prefix) {
			return strings.TrimPrefix(kv, prefix)
		}
	}
	return ""
}

func must(err error) {
	if err != nil {
		if pe := new(os.PathError); errors.As(err, &pe) {
			fmt.Fprintln(os.Stderr, pe.Error())
		} else {
			fmt.Fprintln(os.Stderr, err.Error())
		}
		os.Exit(1)
	}
}

